 1	import { type FC, useState } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import {
 5	  ExpandableSection,
 6	  ExpandableSectionVariant,
 7	  Stack,
 8	  StackItem,
 9	} from '@patternfly/react-core';
10	
11	type NameTemplateBodyProps = {
12	  bodyText: string;
13	  allowedVariables: string[];
14	};
15	
16	const NameTemplateBody: FC<NameTemplateBodyProps> = ({ allowedVariables, bodyText }) => {
17	  const { t } = useForkliftTranslation();
18	  const [isExpanded, setIsExpanded] = useState(false);
19	  return (
20	    <Stack className="pf-v6-u-mb-sm">
21	      <StackItem>{bodyText}</StackItem>
22	      <StackItem>
23	        {t('The VM specific template will override the template set in the plan.')}
24	      </StackItem>
25	      <ExpandableSection
26	        variant={ExpandableSectionVariant.truncate}
27	        toggleText={isExpanded ? t('Hide variables') : t('Show variables')}
28	        isExpanded={isExpanded}
29	        truncateMaxLines={1}
30	        onToggle={(_, expand) => {
31	          setIsExpanded(expand);
32	        }}
33	      >
34	        <StackItem>{t('Variables that can be used for the template:')}</StackItem>
35	        {allowedVariables.map((allowedVariable) => (
36	          <StackItem key={allowedVariable}>{allowedVariable}</StackItem>
37	        ))}
38	      </ExpandableSection>
39	    </Stack>
40	  );
41	};
42	
43	export default NameTemplateBody;

